#include<bits/stdc++.h>
using namespace std;
const int N = 2e5+5 , OK = 0x3f3f3f3f;
int T,n,k,q,cnt;
int a[N],flag[N],id[N],sum[N];
bool dp[105][N],ans[105][N];
int read(){
    int su=0,pp=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){
        if(ch=='-')pp=-1;
        ch=getchar();
    }
    while(ch>='0'&&ch<='9'){
        su=su*10+ch-'0';
        ch=getchar();
    }
    return su*pp;
}
void solve(){
    memset(flag,0,sizeof(flag));//多测不清空，爆零泪两行
    memset(dp,0,sizeof(dp));//多测不清空，爆零泪两行
    memset(ans,0,sizeof(ans));//多测不清空，爆零泪两行
    n=read(),k=read(),q=read();
    cnt=0;
    flag[1]=OK;
    for(int i=1;i<=n;i++){
        int m=read()-1;//-1是因为方便后面操作
        a[++cnt]=read();//先读入第一个数字
        if(a[cnt]==1)dp[0][cnt]=1;//可以作为最开始的开头，那么记录下来
        id[cnt]=cnt;//存下id方便使用
        while(m--){
            a[++cnt]=read();//依次读入后面的数字
            if(a[cnt]==1)dp[0][cnt]=1;//可以作为最开始的开头，那么记录下来
            id[cnt]=id[cnt-1];//这一轮的id均相同，存下来
        }
    }
    for(int i=1;i<=100;i++){//开始遍历
        memset(sum,0,sizeof(sum));//清空前缀和数组
        for(int j=1;j<=cnt;j++)//首先遍历统计前缀和
            sum[j]=sum[j-1]+(flag[a[j]]&&flag[a[j]]!=id[j]);//依靠flag计算前缀和
        memset(flag,0,sizeof(flag));//清空flag数组
        for(int j=1;j<=cnt;j++){//开始求解这一轮i的答案
            dp[i][j]=(sum[j-1]-sum[max(id[j],j-k+1)-1]>0);//先算dp
            if(dp[i][j]){//可以的话
                ans[i][a[j]]=1;//ans一定也可以
                if(!flag[a[j]])flag[a[j]]=id[j];//第一次出现那么记录
                else if(flag[a[j]]!=id[j])flag[a[j]]=OK;//第二次出现了变成OK
            }
        }
    }
    while(q--){
        int r=read(),c=read();
        cout<<ans[r][c]<<"\n";//每次O(1)回答，输出对应ans即可
    }
}
int main(){
    //freopen("chain.in","r",stdin);
    //freopen("chain.out","w",stdout);
    T=read();
    while(T--)solve();
    return 0;
}
